#include <unistd.h>
#include <stdio.h>
#include <stdlib.h>
#include <ctype.h>
#include <math.h>

int main()
{
    int n,m;
    scanf("%d %d", &n, &m);
    int count = 0;
    int a, b = 0;
    for (a = 0; b >= 0; a++)
    {
        b = n - a * a;
        if (a + b * b == m && b >= 0)
            count++;
    }
    printf("%d\n", count);
    return 0;
}

