use std::io;
use std::str::FromStr;

fn get_pair() -> (i32, i32) {
    let mut input = String::new();

    io::stdin().read_line(&mut input).expect("");

    let v = input
        .trim()
        .split_whitespace()
        .map(|s| i32::from_str(s).unwrap())
        .collect::<Vec<_>>();

    (v[0], v[1])
}

fn main() {
    let (n, m) = get_pair();

    let mut c = 0;
    for a in 0..=1000 {
        for b in 0..=100 {
            if a * a + b == n && a + b * b == m {
                c += 1;
            }
        }
    }

    println!("{}", c);
}
